#include <iostream>
#include <vector>
#include <sstream>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    Solution solution;
    cout << solution.solve(nums) << endl;
    return 0;
}

class Solution {
public:
    int solve(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n - 1; ++i) {
            if (n == 1) {
                return nums[0] == nums[0];
            }
            if (nums[i] == nums[i + 1] && nums[i] == nums[i + 2]) {
                return 1;
            }
        }
        return 0;
    }
};
